import React, { useState, useRef, useEffect } from 'react';
// Ensure you have installed the library: npm install @google/generative-ai
import { GoogleGenerativeAI } from "@google/generative-ai";

// 🔑 YOUR NEW API KEY IS INTEGRATED HERE
const API_KEY = "AIzaSyC35RtQVQDpvnavIumd3-Lkt0T8je5iI5w"; 

function ChatBot() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { text: "👋 Hi! I'm the real AI CampusBot. Ask me about projects, errors, or upload limits!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking]);

  // --- AI LOGIC ---
  const generateResponse = async (userQuestion) => {
    try {
      // 1. Initialize the AI
      const genAI = new GoogleGenerativeAI(API_KEY);
      
      // 2. Use the "Flash" model (Fastest & Best for Free Tier)
      const model = genAI.getGenerativeModel({ model: "gemini-pro" });

      // 3. The "Brain" (System Instructions)
      // This tells the AI how to behave and what your project is about.
      const systemContext = `
        You are CampusBot, an AI assistant for the "CampusCanvas" student project repository.
        
        KNOWLEDGE BASE:
        - Project Name: CampusCanvas
        - Tech Stack: React.js, Firebase, Tailwind CSS.
        - Functionality: Students upload projects; Admins approve/reject them.
        - Image Storage: We use Base64 strings (max 1MB) to keep hosting free.
        - Hosting: Vercel (Frontend).
        
        COMMON ERROR SOLUTIONS: 
        * "White Screen" -> Usually a React rendering crash. Refresh the page.
        * "Slow Load" -> Caused by large Base64 images decoding.
        * "Permission Denied" -> User is not logged in as Admin.
        * "File too large" -> Image must be under 1MB.
        
        INSTRUCTIONS:
        - Be helpful, concise, and friendly.
        - If asked for code, provide short React or Firebase snippets.
      `;

      const prompt = `${systemContext}\n\nUser Question: ${userQuestion}\nAnswer:`;

      const result = await model.generateContent(prompt);
      const response = await result.response;
      return response.text();
    } catch (error) {
      console.error("AI Error:", error);
      // This will show the specific error in the chat bubble if something goes wrong
      return `⚠️ Connection Error: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Show User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    // 2. Get AI Response
    const aiText = await generateResponse(input);

    // 3. Show AI Message
    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      
      {/* CHAT WINDOW */}
      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden animate-fade-in-up mb-4">
          
          {/* Header */}
          <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-4 flex justify-between items-center text-white shadow-md">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-1.5 rounded-full backdrop-blur-md">🤖</div>
              <div>
                <h3 className="font-bold text-sm">CampusBot AI</h3>
                <p className="text-[10px] text-indigo-100 opacity-80">Online • Gemini Flash</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 w-8 h-8 rounded-full transition">✕</button>
          </div>

          {/* Messages Area */}
          <div className="flex-1 p-4 overflow-y-auto bg-slate-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-xl text-sm leading-relaxed shadow-sm ${
                  msg.isBot 
                    ? 'bg-white border border-gray-200 text-gray-800 rounded-tl-none' 
                    : 'bg-indigo-600 text-white rounded-tr-none'
                }`}>
                  {/* Markdown-style Code Block Support */}
                  {msg.text.split('```').map((part, i) => 
                    i % 2 === 1 ? (
                      <code key={i} className="block bg-black text-green-400 p-2 rounded text-xs my-2 overflow-x-auto font-mono">
                        {part}
                      </code>
                    ) : (
                      <span key={i}>{part}</span>
                    )
                  )}
                </div>
              </div>
            ))}
            
            {/* Thinking Animation */}
            {isThinking && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-200 p-3 rounded-xl rounded-tl-none shadow-sm flex gap-1">
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." 
              className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500 border border-transparent transition"
            />
            <button 
              onClick={handleSend}
              disabled={isThinking}
              className={`w-10 h-10 rounded-full flex items-center justify-center transition shadow-md ${
                isThinking ? 'bg-gray-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white active:scale-95'
              }`}
            >
              ➤
            </button>
          </div>
        </div>
      )}

      {/* FLOATING BUTTON */}
      {!isOpen && (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-gradient-to-tr from-indigo-600 to-purple-600 hover:scale-110 text-white rounded-full shadow-xl shadow-indigo-500/40 flex items-center justify-center text-3xl transition-all active:scale-95"
        >
          ✨
        </button>
      )}
    </div>
  );
}

export default ChatBot;
